1	import { readFileSync } from "node:fs";
2	import { quote, claim } from "./claim-office.js";
3	
4	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
5	type Damage = { itemType: string; amount: number };
6	type Step =
7	  | { op: "quote"; items: Item[] }
8	  | { op: "claim"; policy: number; incident: { cause: string; damages: Damage[] } };
9	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
10	
11	const STDIN_FD = 0;
12	
13	const scenario: Scenario = JSON.parse(readFileSync(STDIN_FD, "utf-8"));
14	const { yearsWithMHPCO } = scenario.customer;
15	
16	const findPolicyItems = (policyIndex: number): Item[] => {
17	  const policyStep = scenario.steps[policyIndex];
18	  return policyStep.op === "quote" ? policyStep.items : [];
19	};
20	
21	const processStep = (step: Step): object => {
22	  if (step.op === "quote") {
23	    return { premium: quote({ yearsWithMHPCO, items: step.items, applyFirstInsurance: true }) };
24	  }
25	  return claim({ items: findPolicyItems(step.policy), damages: step.incident.damages });
26	};
27	
28	const results = scenario.steps.map(processStep);
29	process.stdout.write(JSON.stringify({ results }));
